parameters.jsonBody:
={{
{
  chat_id: $('Edit Fields').item.json.fromId,
  text: $('Edit Fields3').item.json.output.message 
        + "\n\n" 
        + ($('Edit Fields3').item.json.output["next question"] || ""),
  reply_markup: $('Edit Fields3').item.json.output.answers
    ? {
        inline_keyboard: $('Edit Fields3').item.json.output.answers.reduce((rows, answer, index) => {
          if (index % 2 === 0) rows.push([]);

          rows[rows.length - 1].push({
            text: answer,
            callback_data: answer
          });

          return rows;
        }, [])
      }
    : undefined
}
}}

